import React from 'react'

const Popup = props => {

    const styles = {

        button: {
            backgroundColor: '#A4C717',
            borderColor: '#A4C717',
            width: '100px',
            height: '55px',
            marginLeft: '40px',
            marginTop: '50px',
            fontSize: '17px',
            fontFamily: 'Ubuntu',
            fontWeight: 'bold',
            color: 'white',

        },



    };

    return (
        <div className="popup-box">
            <div className="box boxPopupmin">


                {props.content}

                {props.isClose ?

                    <div style={{ flexDirection: 'row', display: 'flex', justifyContent: 'end', marginTop: '40px' }}>
                        <div>
                            <button
                                className={`buttonStyle activeButtonStyle `}
                                onClick={props.handleClose}
                                style={{ width:'100px' }}
                            >
                                Close
                            </button>
                        </div>
                    </div>
                    :
                    <div style={{ flexDirection: 'row', display: 'flex', justifyContent: 'end', marginTop: '40px' }}>
                        <div>
                            <button
                            
                                className={`buttonStyle activeButtonStyle `}
                                onClick={props.handleYes}
                                style={{ width:'100px' }}
                            >
                                yes
                            </button>
                        </div>

                        <div>
                            <button
                                // style={{ ...styles.button }}
                                className={`buttonStyle  `}
                                onClick={props.handleNo}
                                style={{ width:'100px' }}
                            >
                                No
                            </button>
                        </div>

                    </div>

                }






            </div>
        </div>
    )
}

export default Popup