
import React, { useState } from 'react'

const FilterBoxPopup2 = props => {

     const [filterParms, setFilterParms] = useState({})

    const [datafilter, setDatafilter] = useState(false)
    const [mobilefilter, setMobilefilter] = useState(false)
    const [leadfilter, setLeadfilter] = useState(false)
    const [urnfilter, setUrnfilter] = useState(false)
    const [statusfilter, setStatusfilter] = useState(false)


    const [start_date, setStart_date] = useState(props.currentDate)
    const [end_date, setEnd_date] = useState(props.nextDate)
    const [mobile_no, setMobile_no] = useState('')
    const [lead_id, setLead_id] = useState('')
    const [urn_no, setUrn_no] = useState('')
    const [status, setStatus] = useState('')

    


    const handelleadfilter = (e) => {

        // alert(e.target.id)

        if (e.target.id == "date_filter") {
            setDatafilter(!datafilter)
        } else if (e.target.id == "mobile_no_filter") {
            setMobilefilter(!mobilefilter)
        } else if(e.target.id == "lead_id_filter"){
            setLeadfilter(!leadfilter)
        } else if(e.target.id == "uid_c_filter"){
            setUrnfilter(!urnfilter)
        } else if(e.target.id == "status_filter"){
            setStatusfilter(!statusfilter)
        } 





    }

    const handelApplyFilter = () => {
        
    //    const filterParms = {};

        if (datafilter) {
            filterParms.start_date = start_date;
            filterParms.end_date = end_date;
        }
        if (mobilefilter) {
            filterParms.phone_mobile = mobile_no;
        }
        if (leadfilter) {
            filterParms.lead_id = lead_id;
        }

        if (urnfilter) {
            filterParms.uid_c = urn_no;
        }

        if (statusfilter) {
            filterParms.stage_status_c = status;
        }
        

        console.log("filterParms",filterParms)

        props.handelFilterApply(filterParms)

    }

    const styles = {

        text: {
            fontSize: '16px',
            fontFamily: 'Ubuntu'
        },

        box: {
            width: '98%',
            // height: '40px',
            borderRadius: '6px',
            fontSize: '16px',
            padding: 10,
            border: '1px solid #96c221',
            boxShadow: 'none',
            outline: '1px solid white',
            fontFamily: 'Ubuntu',
        },

        button: {
            backgroundColor: '#A4C717',
            borderColor: '#A4C717',
            width: '100px',
            height: '55px',
            marginLeft: '40px',
            marginTop: '50px',
            fontSize: '17px',
            fontFamily: 'Ubuntu',
            fontWeight: 'bold',
            color: 'white',

        },

        label: {
            color: '#72310C',
            textAlign: 'center',
            fontFamily: 'Ubuntu',
            fontSize: '14px',
            fontWeight: '500',
            position: 'relative',
            top: '7.5px',
            // padding: '15px 15px 15px 0px',
            backgroundColor: '#fff',
            padding: '0px 5px',
            left: '10px',
            // zIndex:'-1',
        }

    };




    return (
        <div className="popup-box">


            <div className="filterbox" style={{ flexDirection: 'column', display: "flex" }}>


                <div style={{ flexDirection: 'row', display: "flex", width: '100%', justifyContent: 'space-between' }}>

                    <div>

                        <p>Filter</p>

                    </div>

                    <div>

                        <p onClick={props.handleClose} >clear</p>
                    </div>


                </div>

                <div style={{ flexDirection: 'row', display: "flex", width: '100%', }}>

                    <div style={{ width: '30%', height: '300px', backgroundColor: '#E9E9E9', borderRadius: '8px' }} >
                        {/* 
                        <button
                            onClick={(e) => handelleadfilter(e)}
                            id="date_filter" style={{ width: "100%", fontFamily: "Ubuntu", fontWeight: '450' }}
                            className={`buttonStyle ${datafilter ? 'activeButtonStyle' : 'buttonStyle'}`}
                        >Date </button> */}


                        <>

                            {/* Data filtert Input ... */}
                            <div style={{ display: 'flex', margin: '10px 5px' }} className='dataFilter'>

                                <input
                                    id="date_filter"
                                    style={{

                                        width: '15px',
                                        height: '15px', fontWeight: '500', textAlign: 'center', color: '#72310C',
                                        textAlign: 'center',
                                        fontFamily: 'Ubuntu',
                                        fontSize: '12px'
                                    }}
                                    type="checkbox"
                                    onClick={(e) => handelleadfilter(e)}
                                    checked={datafilter}

                                // onChange={aggreToAddAdditionalInfo}
                                />
                                Date

                            </div>

                            {/* Mobile filtert Input ... */}
                            <div style={{ display: 'flex', margin: '20px 5px' }} >

                                <input
                                    id="mobile_no_filter"
                                    style={{
                                        width: '15px',
                                        height: '15px', fontWeight: '500', textAlign: 'center', color: '#72310C',
                                        textAlign: 'center',
                                        fontFamily: 'Ubuntu',
                                    }}
                                    type="checkbox"
                                    onClick={(e) => handelleadfilter(e)}
                                    checked={mobilefilter}

                                // checked={additionalInfoCheck}
                                // onChange={aggreToAddAdditionalInfo}
                                />
                                Mobile

                            </div>

                            {/* Lead Id filtert Input ... */}
                            <div style={{ display: 'flex', margin: '20px 5px' }} >

                                <input
                                    id="lead_id_filter"
                                    style={{
                                        width: '15px',
                                        height: '15px', fontWeight: '500', textAlign: 'center', color: '#72310C',
                                        textAlign: 'center',
                                        fontFamily: 'Ubuntu',
                                    }}
                                    type="checkbox"
                                    onClick={(e) => handelleadfilter(e)}
                                    checked={leadfilter}

                                // checked={additionalInfoCheck}
                                // onChange={aggreToAddAdditionalInfo}
                                />
                                Lead ID

                            </div>

                            {/* URN no filtert Input ... */}
                            <div style={{ display: 'flex', margin: '20px 5px' }} >

                                <input
                                    id="uid_c_filter"
                                    style={{
                                        width: '15px',
                                        height: '15px', fontWeight: '500', textAlign: 'center', color: '#72310C',
                                        textAlign: 'center',
                                        fontFamily: 'Ubuntu',
                                    }}
                                    type="checkbox"
                                    onClick={(e) => handelleadfilter(e)}
                                    checked={urnfilter}

                                // checked={additionalInfoCheck}
                                // onChange={aggreToAddAdditionalInfo}
                                />
                                URN No

                            </div>

                            {/* Status filtert Input ... */}
                            <div style={{ display: 'flex', margin: '20px 5px' }} >

                                <input
                                    id="status_filter"
                                    style={{
                                        width: '15px',
                                        height: '15px', fontWeight: '500', textAlign: 'center', color: '#72310C',
                                        textAlign: 'center',
                                        fontFamily: 'Ubuntu',
                                    }}
                                    type="checkbox"
                                    onClick={(e) => handelleadfilter(e)}
                                    checked={statusfilter}

                                // checked={additionalInfoCheck}
                                // onChange={aggreToAddAdditionalInfo}
                                />
                                Status

                            </div>





                        </>
                        {/* <button
                            onClick={(e) => handelleadfilter(e)}
                            id="lead_id_filter" style={{ width: "100%", fontFamily: "Ubuntu", fontWeight: '450' }}
                            className={`buttonStyle ${leadfilter ? 'activeButtonStyle' : 'buttonStyle'}`}
                        >Lead Id </button> */}



                    </div>

                    <div style={{ width: '60%', marginLeft: '10px' }} >

                        {datafilter &&
                            <div style={{ display: 'flex', flexDirection: 'column' }} className='dataFilter' >

                                {/* From Date */}
                                <div className="col " >
                                    <label
                                        htmlFor="from"
                                        style={styles.label}
                                    >From <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="date"
                                        name="from"
                                        className='filterInput'
                                        id='from'
                                        value={props.currentDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setStart_date(e.target.value))}
                                    />
                                </div>

                                {/* To date */}
                                <div className="col " >
                                    <label
                                        htmlFor="to"
                                        style={styles.label}
                                    >To <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="date"
                                        name="to"
                                        id='to'
                                        className='filterInput'
                                        value={props.nextDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setEnd_date(e.target.value))}
                                    />
                                </div>




                            </div>
                        }

                        {mobilefilter &&

                            <div style={{ display: 'flex', flexDirection: 'column' }} >

                               
                                <div className="col " >
                                    <label
                                        htmlFor="mobile_no"
                                        style={styles.label}
                                    >Mobile No<span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="text"
                                        name="mobile_no"
                                        id='mobile_no'
                                        className='filterInput'
                                        // value={currentDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setMobile_no(e.target.value))}
                                    />
                                </div>



                            </div>
                        }

                        {leadfilter &&

                            <div style={{ display: 'flex', flexDirection: 'column' }} >

                               
                                <div className="col " >
                                    <label
                                        htmlFor="lead_id"
                                        style={styles.label}
                                    >Lead Id<span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="text"
                                        name="lead_id"
                                        id='lead_id'
                                        className='filterInput'
                                        // value={currentDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setLead_id(e.target.value))}
                                    />
                                </div>



                            </div>
                        }

                        {urnfilter &&

                            <div style={{ display: 'flex', flexDirection: 'column' }} >

                               
                                <div className="col " >
                                    <label
                                        htmlFor="unr_no"
                                        style={styles.label}
                                    >URN <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="text"
                                        name="unr_no"
                                        id='urn_no'
                                        className='filterInput'
                                        // value={currentDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setUrn_no(e.target.value))}
                                    />
                                </div>



                            </div>
                        }

                        {statusfilter &&

                            <div style={{ display: 'flex', flexDirection: 'column' }} >

                               
                                <div className="col " >
                                    <label
                                        htmlFor="status"
                                        style={styles.label}
                                    >Status <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                                    <input
                                        style={{ ...styles.box }}
                                        type="text"
                                        name="status"
                                        id='status'
                                        className='filterInput'
                                        // value={currentDate}
                                        // onChange={props.handleFilterSelect}
                                        onChange={(e) => (setStatus(e.target.value))}
                                    />
                                </div>



                            </div>
                        }

                    </div>


                </div>



                <div style={{ flexDirection: 'row', display: 'flex', justifyContent: 'end', marginTop: '40px' }}>
                    <div>
                        <button
                            style={{ width: "100px" }}
                            className={`buttonStyle activeButtonStyle `}
                            onClick={() => {handelApplyFilter() }}
                        >
                            Apply
                        </button>
                    </div>
                </div>

            </div>



        </div>

    )
}

export default FilterBoxPopup2