import React from 'react'
import { useEffect, useMemo, useState } from "react";
import { eligibleProductHeaders, thirdPartyProductHeaders } from "../../constants/tableHeaders";
import { useTable, useSortBy, useGlobalFilter, useFilters, usePagination } from "react-table";
import { useNavigate } from "react-router-dom";


const ElgLoanProductTable = ({ handleClick, tableData, interestedFinalProduct, updateReqBody, handleChange }) => {
  const columns = useMemo(() => eligibleProductHeaders, []); // memoize before adding to useTable hook
  const data = useMemo(() => [...tableData], [tableData]);

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = useTable({
    columns, // useTable hook takes in memoized columns and data to be displayed
    data,
  });





  const [editable, setEditable] = useState(false);
  const [inputValue, setInputValue] = useState("requested amount");

  const handleEdit = () => {

    setEditable(true);
  };

  const handleSave = () => {
    setEditable(false);
  };

  const handleInputChange = (e) => {
    setInputValue(e.target.value);
  };
  // const styles = {

  //   box: {
  //     margin:"auto",
  //     border: "none", 
  //       // width: '100%',
  //       // height: '40px',
  //       // fontSize: '19px',
  //       // padding: 10,
  //       // // border: '1px solid #96c221',
  //       // boxShadow: 'none',
  //       // outline: '1px solid white',
  //       // fontFamily: 'Ubuntu',
  //   },
  // }


  return (
    <>
      {/* apply the table props */}
      <table {...getTableProps()}>
        <thead>
          {
            // Loop over the header rows
            headerGroups.map((headerGroup) => (
              // Apply the header row props
              <tr {...headerGroup.getHeaderGroupProps()}>
                {
                  // Loop over the headers in each row
                  headerGroup.headers.map((column) => (
                    // Apply the header cell props
                    <th {...column.getHeaderProps()}>{column.render("Header")}</th>
                  ))
                }
                <th>Requested Amount</th>
              </tr>
            ))
          }
        </thead>
        {/* Apply the table body props */}
        <tbody {...getTableBodyProps()}>
          {
            // Loop over the table rows
            rows.map((row, i) => {
              // Prepare the row for display
              prepareRow(row);
              return (
                <>
                  <tr {...row.getRowProps()}
                    style={{
                      backgroundColor: row.values.description === interestedFinalProduct ? '#A2C617' : '#FFF',
                      color: row.values.description === interestedFinalProduct ? '#FFF' : 'black',
                    }}
                    onClick={() => {
                      handleClick(row.values)
                    }}

                  >
                    {
                      // Loop over the rows cells
                      row.cells.map((cell) => {
                        // Apply the cell props
                        return <td {...cell.getCellProps()}>{cell.render("Cell")}</td>;
                      })
                    }
                    <td
                      style={{padding:"0px"}}
                      className='row'
                    >
                      {row.values.description === interestedFinalProduct && (
                      
                          <input
                            // className='smallTableInput'
                            style={{
                              // ...styles.box,
                              padding:"5px",

                              margin:"auto",
                              border: "none", 
                              color:
                                updateReqBody.required_loan_amount >=  parseInt(row.values.minloanamount) &&
                                updateReqBody.required_loan_amount <= parseInt(row.values.maxloanamount)
                                  ? "green"
                                  : "rgba(251,0, 0,0.7)",
                             
                            }}
                            className='col-lg-12 col-md-12 col-sm-12 smallTableInput'
                            type="number"
                            name="required_loan_amount"
                            id="required_loan_amount"
                            value={updateReqBody != undefined || updateReqBody.required_loan_amount != 0 ? updateReqBody.required_loan_amount :" "}
                            onChange={handleChange}
                           
                          />
                       
                      ) }
                    </td>


                  </tr>





                  {/* <tr
                    {...row.getRowProps()} 
                    style={{
                      backgroundColor: row.values.description === interestedFinalProduct ? '#A2C617' : '#FFF',
                      color:row.values.description === interestedFinalProduct ? '#FFF' : 'black',
                    }}
                    onClick={() => {
                      handleClick(row.values)
                    }}

                  >
                    {
                      row.cells.map((cell) => {
                        // Apply the cell props
                        return <td {...cell.getCellProps()}>{cell.render("Cell")}</td>;
                      })
                    }
                    <td
                      style={{
                        // backgroundColor:
                        //   updateReqBody.required_loan_amount < rows.values.minimum_amount || updateReqBody.required_loan_amount > rows.values.maxloanamount
                        //     ? "red"
                        //     : "A2C617"
                      }}
                    >
                      {editable ? (<><input
                        style={{}}
                        type="number"
                        name="required_loan_amount"
                        id="required_loan_amount"
                        value={updateReqBody != undefined ? updateReqBody.required_loan_amount : ''}
                        onChange={handleChange}
                      /> <button onClick={handleSave(row.values.description)}>Save</button></>) : (
                        <div>
                          {updateReqBody.required_loan_amount}
                          <button onClick={handleEdit(row.values.description)}>Edit</button>
                        </div>
                      )}
                    </td>
                  </tr > */}
                </>
              );
            })
          }
        </tbody>
      </table >
    </>
  );
};

export default ElgLoanProductTable