import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router';
import ArrowLogo from '../components/ArrowLogo'
import { mainOptions, subOptions, languageOptions } from '../constants/masterData'
import { wrapperURL } from '../constants/ConstURLproperties';
import axios from 'axios';

const EssentialInfo = ({ handleChange, ReqBody, handleSearch, disabledDataCheck, searchDataResultInFlsh }) => {

    const [mainSelection, setMainSelection] = useState('');
    const [subSelection, setSubSelection] = useState('');

    const [disabledData, setdisabledData] = useState();
    const [villagesPincode, setVillagesPincode] = useState([]);


    const styles = {

        text: {
            fontSize: '16px',
            fontFamily: 'Ubuntu'
        },

        box: {
            width: '98%',
            height: '40px',
            borderRadius: '6px',
            fontSize: '16px',
            padding: 10,
            border: '1px solid #96c221',
            boxShadow: 'none',
            outline: '1px solid white',
            fontFamily: 'Ubuntu',
        },

        button: {
            backgroundColor: '#A4C717',
            borderColor: '#A4C717',
            width: '350px',
            height: '55px',
            marginLeft: '40px',
            marginTop: '30px',
            fontSize: '17px',
            fontFamily: 'Ubuntu',
            fontWeight: 'bold',
            color: 'white',
        },


        label: {
            color: '#72310C',
            textAlign: 'center',
            fontFamily: 'Ubuntu',
            fontSize: '14px',
            fontWeight: '500',
            position: 'relative',
            top: '7.5px',
            // padding: '15px 15px 15px 0px',
            backgroundColor: '#fff',
            padding: '0px 5px',
            left: '10px',
            // zIndex:'-1',
        }

    };

    // phone_mobile: '', first_name: '', last_name: '',
    // birthdate: '', gender: '', pincode: '',
    // branch_name: '', urn: '', language: '',
    // customer_interested: '', loan_purpose: ''

    useEffect(() => {

        console.log("use effect called ......")
        console.log("use effect called searchDataResultInFlsh ......", disabledDataCheck)
        console.log("use effect called searchDataResultInFlsh......", searchDataResultInFlsh)

        // console.log("Village pin code ......", villagesPincode)


        setdisabledData()

        disabledDataCheck && setdisabledData(ReqBody)

        getVillageListAPICall(localStorage.getItem('branch_code'))
            .then((response) => {

                console.log(response.data)
                if (response.data.code == '200') {

                    console.log("data .... ", response.data.data);
                    console.log("data branch .... ", response.data.data[localStorage.getItem('branch_code')]);

                    const dataObject = response.data.data[localStorage.getItem('branch_code')]; // Access the array under the "3048" key
                    const villages = dataObject.map((village) => ({
                        name: village.name,
                        pincode: village.pincode
                    }));
                    setVillagesPincode(villages);

                    // setIsLoding(false)
                } else {
                    // setIsPopupOpen(!isPopupOpen);
                    // setPopupContent(response.data.message)
                    // setIsClose(true)
                }

            })
            .catch(function (error) {
                console.log(error);
            });

    }, [disabledDataCheck])

    const getVillageListAPICall = (branchCode) => {

        return axios({
            method: 'GET',
            // url: `${dvarakgfsURL}/api/sharelib/enrollment/customer?option=findCustomer&findBy=${findBy}&findByValue=${findByValue}`,
            // url: `${dvarakgfsURL}/getpartnerapi?findby=${findBy}&value=${findByValue}`,
            // 'http://10.10.0.40:9000/api/getpartnerapi?findby=mobile&value=9938660274
            // url: `https://sandbox.dvarakgfs.com/api/sharelib/master/branches?option=branchServiceAreaByBranchCodes&branch_codes=3048`,
            url: `${wrapperURL}/villages?branchCode=${branchCode}`,
            // 

            headers: {
                'accept': '*/*',
                // 'X-Authorization':'4a80e43bd1891cc9bbf6ca8ad8e2cc4a',
                // 'X-Auth-source':'SynoCRM',
            },
        })

    }

    return (
        <>

            <div className="row" style={{ display: 'flex', flexWrap: 'wrap' }} >

                {/* Mobile Number */}
                <div className="col" >
                    <label
                        htmlFor="Mobile Number"
                        style={styles.label}
                    >Mobile Number<span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                    <input
                        style={{ ...styles.box, boxShadow: 'none' }}
                        type="text"
                        name="phone_mobile"
                        value={ReqBody != undefined ? ReqBody.phone_mobile : ''}
                        id="phone_mobile"
                        // disabled={ReqBody !== undefined && ReqBody.phone_mobile !== '' &&  ReqBody.phone_mobile.length > 10? true:false}
                        onChange={(e) => {

                            const regex = /^[0-9]{1,10}$/; // Regular expression to allow only alphabets

                            if (regex.test(e.target.value) || e.target.value === "") {

                                handleChange(e)
                                // setdisabledData()

                            }

                            if (e.target.value.length == 10) {
                                // alert(e.target.value)
                                handleSearch("mobile", e.target.value)
                                // disabledDataCheck && setdisabledData(ReqBody)
                                // searchDataResultInFlsh && setdisabledData(ReqBody)

                                // setdisabledDataCheck(true)
                            } else {
                                setdisabledData()
                            }

                            // handleChange
                        }

                        }
                    />
                </div>

                {/* Date of Birth */}
                <div className="col " >
                    <label
                        htmlFor="birthdate"
                        style={{
                            ...styles.label,
                            zIndex: `${disabledData !== undefined && disabledData.first_name !== '' ? 1 : 'auto'}`
                        }}
                    >Date of Birth <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                    <input
                        style={{ ...styles.box }}
                        type="date"
                        name="birthdate"
                        id='birthdate'
                        value={ReqBody != undefined ? ReqBody.birthdate : ''}
                        disabled={ReqBody?.phone_mobile?.length <= 9 ? false : disabledData !== undefined && disabledData.birthdate !== '' ? true : false}
                        onChange={handleChange}
                    />
                </div>

                {/* First Name */}
                <div className="col" >
                    <label
                        htmlFor="first_name"
                        style={{
                            ...styles.label,
                            zIndex: `${disabledData !== undefined && disabledData.first_name !== '' ? 1 : 'auto'}`
                        }}
                        disabled={true}
                    >Customer Name<span style={{ fontSize: '18px', color: 'red' }}> * </span></label>
                    <input
                        style={styles.box}
                        type="text"
                        name="first_name"
                        id='first_name'
                        value={ReqBody != undefined ? ReqBody.first_name : ''}
                        disabled={ReqBody?.phone_mobile?.length <= 9 ? false : disabledData !== undefined && disabledData.first_name !== '' ? true : false}
                        // disabled={true}
                        onChange={(e) => {
                            const regex = /^[A-Za-z ]+$/; // Regular expression to allow only alphabets

                            if (regex.test(e.target.value) || e.target.value === "") {

                                handleChange(e)

                            }
                        }}
                    />
                </div>

                {/* Last Name */}
                {/* <div className="col"  >
                    <label
                        htmlFor="last_name"
                        style={styles.label}
                    >Last Name:</label>
                    <input
                        style={styles.box}
                        type="text"
                        name="last_name"
                        id='last_name'
                        value={ReqBody != undefined ? ReqBody.last_name : ''}
                        disabled={ReqBody !== undefined && ReqBody.last_name !== '' ? false:true}
                        onChange={(e)=>{
                            const regex = /^[A-Za-z ]+$/; // Regular expression to allow only alphabets

                            if (regex.test(e.target.value) || e.target.value === "") {

                                handleChange(e)

                            }
                        }}
                        // disabled={ReqBody != undefined && ReqBody.first_name != undefined
                        //     && ReqBody.first_name != null && ReqBody.first_name != '' ? true : false

                        // }
                    />
                </div> */}

                {/* Gender */}
                <div className="col"  >
                    <label
                        htmlFor="gender"
                        style={styles.label}
                    >Gender <span style={{ fontSize: '18px', color: 'red' }}> * </span>  </label>
                    <div style={styles.box}>
                        <select
                            name="gender"
                            id='gender'
                            value={ReqBody != undefined ? ReqBody.gender : ''}
                            onChange={handleChange}
                            disabled={disabledData !== undefined && disabledData.gender !== '' ? true : false}
                            style={{ flex: 1, width: '100%', height: '100%', border: 0, outline: '1px solid white', fontSize: '16px', fontFamily: 'Ubuntu' }}
                        >   <option value="" style={{ ...styles.box, ...styles.text }}>-- Select an option -- </option>
                            <option value="male" style={{ ...styles.box, ...styles.text }}>Male</option>
                            <option value="female" style={{ ...styles.box, ...styles.text }}>Female</option>
                            <option value="other" style={{ ...styles.box, ...styles.text }}>Other</option>

                        </select>
                    </div>
                </div>

                {/* URN */}
                <div className="col" >
                    <label
                        htmlFor="urn"
                        style={{
                            ...styles.label,
                            zIndex: `${disabledData !== undefined && disabledData.first_name !== '' ? 1 : 'auto'}`
                        }}
                    >URN </label>
                    <input
                        style={styles.box}
                        type="text"
                        name="urn"
                        id='urn'
                        value={ReqBody != undefined ? ReqBody.urn : ''}
                        disabled={disabledData !== undefined && disabledData.urn !== '' && disabledData.urn !== "" ? true : false}
                        onChange={(e) => {

                            const regex = /^[0-9]{1,16}$/; // Regular expression to allow only alphabets

                            if (regex.test(e.target.value) || e.target.value === "") {

                                handleChange(e)

                            }

                            if (e.target.value.length == 16) {
                                // alert(e.target.value)

                                handleSearch("urn", e.target.value)
                                // setdisabledDataCheck(true)
                            }

                            // handleChange
                        }

                        }
                    />
                </div>


                {/* Voter Id */}
                <div className="col" >
                    <label
                        htmlFor="voterid"
                        style={{
                            ...styles.label,
                            zIndex: `${disabledData !== undefined && disabledData.first_name !== '' ? 1 : 'auto'}`
                        }}
                    >Voter ID 
                    {ReqBody?.lead_source === "MITRA" && <span style={{ fontSize: '18px', color: 'red' }}> * </span> } </label>
                    {/* {<span style={{ fontSize: '18px', color: 'red' }}> * </span> } </label> */}
                   
                    <input
                        // onKeyPress={(event) => {

                        //     const regex = /^[A-Za-z]+$/;

                        //     if (regex.test(event.key)) {
                        //         event.preventDefault();
                        //     }
                        // }} 
                        style={styles.box}
                        type="text"
                        name="voterid"
                        id='voterid'
                        value={ReqBody != undefined ? ReqBody.voterid : ''}
                        disabled={disabledData !== undefined && disabledData.voterid !== '' ? true : false}
                        onChange={handleChange}
                    />
                </div>


                {/* Village list*/}
                <div className="col">
                    {/* <label
                        htmlFor="language"
                        style={styles.label}
                    >LANGUAGE <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                    <input
                        style={styles.box}
                        type="text"
                        name="language"
                        id='language'
                        value={ReqBody != undefined ? ReqBody.language : ''}
                        onChange={handleChange}
                    /> */}



                    <label
                        htmlFor="village"
                        style={styles.label}
                    >Village<span style={{ fontSize: '18px', color: 'red' }}> * </span></label>
                    <div style={styles.box}>


                        <select
                            name="village"
                            id='village'
                            onChange={handleChange}
                            value={ReqBody != undefined ? ReqBody.village_name : ''}
                            disabled={disabledData !== undefined && disabledData.language !== '' ? true : false}
                            style={{ flex: 1, width: '100%', height: '100%', border: 0, outline: '1px solid white', fontSize: '16px', fontFamily: 'Ubuntu' }}>
                            <option value="" style={{ ...styles.box, ...styles.text }}>-- Select an option -- </option>
                            {/* {villagesPincode?.map(({name , pincode}) => (
                                <option key={name} value={name} data_value={pincode} style={{ ...styles.box, ...styles.text }}>
                                    {name}
                                </option>
                            ))} */}
                            {/* Render ReqBody.village if it's not in villagesPincode */}
                            {ReqBody?.village_name && !villagesPincode?.some(v => v.name === ReqBody.village_name) && (
                                <option value={ReqBody.village_name} style={{ ...styles.box, ...styles.text }}>
                                    {ReqBody.village_name}
                                </option>
                            )}

                            {/* Render options from villagesPincode */}
                            {villagesPincode?.map(({ name, pincode }) => (
                                <option key={name} value={name} data_value={pincode} style={{ ...styles.box, ...styles.text }}>
                                    {name}
                                </option>
                            ))}

                        </select>


                    </div>

                </div>

                {/* Pincode */}
                <div className="col" >
                    <label
                        htmlFor="pincode"
                        style={{
                            ...styles.label,
                            zIndex: `${disabledData !== undefined && disabledData.first_name !== '' ? 1 : 'auto'}`
                        }}
                    >Pincode</label>
                    <input
                        onKeyPress={(event) => {



                            if (!/[0-9]/.test(event.key)) {
                                event.preventDefault();
                            }
                        }} style={styles.box}
                        type="text"
                        name="pincode"
                        id='pincode'
                        value={ReqBody != undefined ? ReqBody.pincode : ''}
                        disabled={disabledData !== undefined && disabledData.pincode !== '' ? true : false}
                        onChange={handleChange}
                    />
                </div>

                {/* Language */}
                <div className="col">
                    {/* <label
                        htmlFor="language"
                        style={styles.label}
                    >LANGUAGE <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                    <input
                        style={styles.box}
                        type="text"
                        name="language"
                        id='language'
                        value={ReqBody != undefined ? ReqBody.language : ''}
                        onChange={handleChange}
                    /> */}



                    <label
                        htmlFor="language"
                        style={styles.label}
                    >Language<span style={{ fontSize: '18px', color: 'red' }}> * </span></label>
                    <div style={styles.box}>


                        <select
                            name="language"
                            id='language'
                            onChange={handleChange}
                            value={ReqBody != undefined ? ReqBody.language : ''}
                            disabled={disabledData !== undefined && disabledData.language !== '' ? true : false}
                            style={{ flex: 1, width: '100%', height: '100%', border: 0, outline: '1px solid white', fontSize: '16px', fontFamily: 'Ubuntu' }}>
                            <option value="" style={{ ...styles.box, ...styles.text }}>-- Select an option -- </option>
                            {languageOptions.map((option) => (
                                <option key={option} value={option?.toUpperCase()} style={{ ...styles.box, ...styles.text }}>
                                    {option}
                                </option>
                            ))}


                        </select>


                    </div>

                </div>

                {/* Customer Interested In */}
                <div className="col"  >
                    <label
                        htmlFor="customer_interested"
                        style={styles.label}
                    >Customer Interested In<span style={{ fontSize: '18px', color: 'red' }}> * </span></label>
                    <div style={styles.box}>


                        <select
                            name="customer_interested"
                            id='customer_interested'
                            onChange={handleChange}
                            value={ReqBody != undefined ? ReqBody.customer_interested : ''}
                            // onChange={handleMainSelectChange}
                            style={{ flex: 1, width: '100%', height: '100%', border: 0, outline: '1px solid white', fontSize: '16px', fontFamily: 'Ubuntu' }}>
                            <option value="" style={{ ...styles.box, ...styles.text }}> -- Select an option -- </option>
                            {mainOptions.map((option) => (
                                <option key={option.key} value={option.discription} data_value={option.key} style={{ ...styles.box, ...styles.text }}>
                                    {option.discription}
                                </option>
                            ))}


                        </select>
                    </div>
                </div>

                {/*Purpose Of Loan*/}
                <div className="col" >
                    <label
                        htmlFor="loan_purpose"
                        style={styles.label}
                    >Purpose Of Loan<span style={{ fontSize: '18px', color: 'red' }}> * </span></label>
                    <div style={styles.box}>
                        <select
                            name="loan_purpose"
                            id='loan_purpose'
                            value={ReqBody != undefined ? ReqBody.loan_purpose : ''}
                            onChange={handleChange}
                            style={{ flex: 1, width: '100%', height: '100%', border: 0, outline: '1px solid white', fontSize: '16px', fontFamily: 'Ubuntu' }}>
                            <option value="">-- Select an option --</option>
                            {subOptions[ReqBody != undefined ? ReqBody.customer_interested : '']?.map((option) => (
                                <option key={option} value={option.discription} style={{ ...styles.box, ...styles.text }} data_value={option.key} >
                                    {option.discription}
                                </option>
                            ))}

                        </select>
                    </div>
                </div>

            </div>


            {/* <div className="row" style={{ display: 'flex', flexWrap: 'wrap'}} > */}

            {/* <div className="col" style={{ width: '100%', margin: '0px 20px', padding: '0px 20px' }} >
                    <label
                        htmlFor="branch_name"
                        style={styles.label}
                    >BRANCH  NAME </label>
                    <input
                        style={styles.box}
                        type="text"
                        name="branch_name"
                        id='branch_name'
                        value={ReqBody != undefined ? ReqBody.branch_name : ''}
                        onChange={handleChange}
                    />
                </div> */}



            {/* <div className="col" style={{ width: '100%', margin: '0px 20px', padding: '0px 20px' }} >
                    <label
                        htmlFor="MOBILE NUMBER"
                        style={styles.label}
                    >MOBILE NUMBER <span style={{ fontSize: '18px', color: 'red' }}> * </span> </label>
                    <input
                        style={{ ...styles.box, boxShadow: 'none' }}
                        type="text"
                        name="phone_mobile"
                        value={ReqBody != undefined ? ReqBody.phone_mobile : ''}
                        id="phone_mobile"
                        onChange={handleChange}
                    />
                </div> */}



            {/* </div>


            <div className="row" style={{
                display: 'flex',
                flexWrap: 'wrap',
                width: '100%',
                margin: '0 auto',
                marginTop: '30px',
                paddingBottom:'30px'

            }} > */}





            {/* </div> */}


        </>
    )
}

export default EssentialInfo