function formattedDatefunc(unformattedDate) {

  // Input date string
  var inputDateString = unformattedDate;

  // Parse the input date string
  var inputDate = new Date(inputDateString);

  // Extract the date components
  var day = inputDate.getDate();
  var month = inputDate.getMonth() + 1; // Months are zero-based, so add 1
  var year = inputDate.getFullYear();

  // Format the date components to dd/mm/yyyy
  var formattedDate = `${day.toString().padStart(2, '0')}/${month.toString().padStart(2, '0')}/${year}`;

  // Output the formatted date
  console.log(formattedDate);
  return formattedDate;

}

