import React from 'react'
import { useEffect, useMemo, useState } from "react";
import { leadHeaders } from "../../constants/tableHeaders";
import { useTable, useSortBy, useGlobalFilter, useFilters, usePagination } from "react-table";
import { useNavigate } from "react-router-dom";
import logo from '../../assets/logo.svg'

import logarrow_drop_down from '../../assets/arrow_drop_down.svg'
import arrow_drop_up from '../../assets/arrow_drop_up.svg'


const LeadsTable = ({ mockData, onRowClick }) => {

  const styles = {

    box: {
      alignSelf: 'end',
      height: '52px',
      alignItems: 'center',
      display: 'flex',
    },
    paginationHeader: {
      color: '#878787',
      textAlign: 'center',
      fontFamily: 'Ubuntu',
      fontSize: '13px',
      fontWeight: '400',
      letterSpacing: '-0.333px',
      textTransform: 'capitalize',
      margin: '0px 10px'
    },


  };

  const columns = useMemo(() => leadHeaders, []); // memoize before adding to useTable hook
  const data = useMemo(() => [...mockData], [mockData]);

  
  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow,
    page,
    canPreviousPage,
    canNextPage,
    pageOptions,
    pageCount,
    gotoPage,
    nextPage,
    previousPage,
    setPageSize,
    state: { pageIndex, pageSize, globalFilter },
  } = useTable(
    {
      columns,
      data,
      initialState: { sortBy: [{ id: 'defaultSortColumnId' }] },
    },

    useFilters,
    useSortBy,
    usePagination,
  );


  const navigate = useNavigate();

  console.log("pageCount" , pageCount)

  const numberOfPages = []

  const [arrayOfCurrentpages, setArrayOfCurrentpages] = useState([])


  useEffect(() => {
    let tempNumberOfPages = [...numberOfPages]

    if (pageCount > 0 &&  pageCount<=1 ) {
      tempNumberOfPages = [1,]
    } else if(pageCount >= 0 && pageCount <= 2){
      tempNumberOfPages = [1, 2]
    } else if(pageCount > 2){
      if(pageIndex > 2){
        tempNumberOfPages = [1, 2, '...' , pageIndex+1, '...', pageCount]
      } else {
        tempNumberOfPages = [1, 2, 3, '...', pageCount]
      }
    }
    
    // {

    //   tempNumberOfPages = [1, 2, 3,  '...', pageCount]
    // }

    setArrayOfCurrentpages(tempNumberOfPages)
  }, [pageIndex, pageCount])

 

  return (
    <>
      {/* <div style={styles.box}>
        <p style={styles.paginationHeader}>
          showing
        </p>

        <select name="page" onChange={(e)=>{
          gotoPage(e.target.value)
        }}>
          {pageOptions.map((page, index) => (
            <option key={index} value={page} > {page + 1} </option>

          ))}
        </select>

        <p style={styles.paginationHeader}>

          of {"  "} {pageOptions.length}  {" "} results
        </p>
      </div> */}

      {/* apply the table props */}
      <table {...getTableProps()}>
        <thead >
          {
            // Loop over the header rows
            headerGroups.map((headerGroup) => (
              // Apply the header row props
              <tr {...headerGroup.getHeaderGroupProps()} >
                {
                  // Loop over the headers in each row
                  headerGroup.headers.map((column) => (
                    // Apply the header cell props
                    <th {...column.getHeaderProps()} style={{

                      color: '#000'
                    }}>{column.render("Header")}
                      <span  {...column.getHeaderProps(column.getSortByToggleProps())}>
                        {
                          (column.isSortedDesc ? 
                              <img src={logarrow_drop_down} alt="down" />
                            : <img src={arrow_drop_up} alt="up" />)
                        }
                      </span>
                      <div>{column.canFilter ? column.render('Filter') : null}</div>
                    </th>
                  ))
                }
              </tr>
            ))
          }
        </thead>
        {/* Apply the table body props */}
        <tbody {...getTableBodyProps()}>
          {
            // Loop over the table rows
            page.map((row, i) => {
              // Prepare the row for display
              prepareRow(row);
              return (

               
                <tr {...row.getRowProps()}

                  onClick={() => {
                    
                    onRowClick(row.values)

                    // console.log(row.values)
                    // if(row.values.stage == "lead") {
                    //     navigate("/createLead" , { state: row.values })
                    // } else if(row.values.stage == "opportunity"){

                    // }

                    // navigate("/createLead" , { state: row.values });
                  }}

                >
                  {
                    // Loop over the rows cells
                    row.cells.map((cell) => {
                      // Apply the cell props
                      return <td {...cell.getCellProps()}
                      >{cell.render("Cell")} </td>;
                    })
                  }

                </tr>
              );
            })
          }
        </tbody>
      </table>

      <div style={styles.box}>
        <a style={styles.paginationHeader} onClick={() => gotoPage(0)} disabled={!canPreviousPage}>
          {"<"}
        </a>{" "}
        <a style={styles.paginationHeader} onClick={() => {
          previousPage()
          console.log(pageIndex)
        }} disabled={!canPreviousPage}>
          {"Prev"}
        </a>{" "}

        {arrayOfCurrentpages.map((page, index) => (
          <button
            key={index}
            onClick={() => {
              gotoPage(page)

            }}
            href="#"
            className={`${pageIndex === index ? 'paginationActiNums' : 'paginationNums'}`}
          >
            {page}
          </button>
        ))}

        <a style={styles.paginationHeader} onClick={() => nextPage()} disabled={!canNextPage}>
          {"Next"}
        </a>{" "}
        <a style={styles.paginationHeader} onClick={() => gotoPage(pageCount - 1)} disabled={!canNextPage}>
          {">"}
        </a>{" "}

        {/* <span>
            | Go to page:{""}
            <input
              type="number"
              defaultValue={pageIndex + 1}
              onChange={(e) => {
                const page = e.target.value ? Number(e.target.value) - 1 : 0;
                gotoPage(page);
              }}
              style={{ width: "100px" }}
            />
          </span>{" "} */}
        {/* <select
            value={pageSize}
            onChange={(e) => {
              setPageSize(Number(e.target.value));
            }}
          >
            {[10, 20, 30, 40, 50].map((pageSize) => (
              <option key={pageSize} value={pageSize}>
                Show {pageSize}
              </option>
            ))}
          </select> */}
      </div>
    </>
  );
};
export default LeadsTable