import React from 'react'
import { BrowserRouter as Router, Route, Routes, BrowserRouter } from 'react-router-dom';
import Home from './screens/Home'
import Header from './components/Header';
import CreateLeadScreen from './screens/CreateLeadScreen';
import "@fontsource/ubuntu"; // Defaults to weight 400
import "@fontsource/ubuntu/500.css"; // Specify weight
import "@fontsource/ubuntu/500-italic.css"; // Specify weight and style

const App = () => {
  return (

    <Router basename={'/leadWebApp'}  > 
     
      <Routes>
        <Route exact path="/" element={<Home />} />
        <Route exact path="/createLead" element={<CreateLeadScreen />} />
      </Routes>
    </Router> 
  )
}

export default App