import React from 'react'
import loading  from "../assets/loading.gif";


const ApiLoading = props => {
    return (
        <div className="popup-box">
            <div className="loadingBox">
                <img 
                    src={loading}
                    alt='Loading'
                    style={{
                        width:'80px',
                        height:'80px'
                    }}
                />
            </div>
        </div>
    )
}

export default ApiLoading